var currentPluginId = 0; var reviewRating = 0; function loadPlugins() { const search = document.getElementById('plugin-search').value || ''; const category = document.getElementById('plugin-category').value || ''; const type = document.getElementById('plugin-type').value || ''; fetch('/api/plugins?' + new URLSearchParams({ search, category, type })) .then(r => r.json()) .then(data => { if (data.success && data.data) { renderPlugins(data.data); updateStats(data.data); } }) .catch(err => showToast('加载插件失败', 'error')); } function renderPlugins(plugins) { const container = document.getElementById('plugins-list'); if (!plugins || plugins.length === 0) { container.innerHTML = '<div class="text-center py-12 text-slate-400"><i class="fa-solid fa-plug text-4xl mb-3"></i><div>暂无插件</div></div>'; return; } container.innerHTML = plugins.map(p => { const categoryMap = { 'recon': 'bg-cyan-100 dark:bg-cyan-900/40 text-cyan-700 dark:text-cyan-300', 'privesc': 'bg-amber-100 dark:bg-amber-900/40 text-amber-700 dark:text-amber-300', 'lateral': 'bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300', 'report': 'bg-purple-100 dark:bg-purple-900/40 text-purple-700 dark:text-purple-300', 'automation': 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300', 'utility': 'bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-300', }; const categoryLabel = p.category || 'utility'; const categoryColor = categoryMap[categoryLabel] || categoryMap['utility']; const categoryText = { 'recon': '侦察', 'privesc': '提权', 'lateral': '横向移动', 'report': '报告', 'automation': '自动化', 'utility': '工具' }[categoryLabel] || categoryLabel; return `<div class="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl shadow-sm overflow-hidden hover:shadow-md transition-shadow"> <div class="p-4"> <div class="flex items-start justify-between"> <div class="flex-1"> <div class="flex items-center gap-2 mb-1"> <span class="text-xs font-semibold px-2 py-0.5 rounded-full ${categoryColor}">${categoryText}</span> <span class="text-[10px] px-2 py-0.5 bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full">${p.type || 'unknown'}</span> ${p.update_available ? '<span class="text-[10px] px-2 py-0.5 bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-300 rounded-full"><i class="fa-solid fa-circle-up mr-0.5"></i>更新可用</span>' : ''} </div> <h3 class="font-semibold text-slate-900 dark:text-slate-100 text-sm cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400" onclick="showPluginDetail(${p.id})">${p.name}</h3> <div class="text-xs text-slate-500 dark:text-slate-400 mt-0.5">v${p.version} · ${p.author || 'unknown'}</div> <p class="text-xs text-slate-600 dark:text-slate-300 mt-2 line-clamp-2">${p.description || '无描述'}</p> </div> <div class="flex flex-col items-end gap-2 ml-4"> <div class="flex items-center gap-1 text-xs text-amber-600"> <i class="fa-solid fa-star"></i> <span>${p.rating_overall || '0.0'}</span> <span class="text-slate-400">(${p.rating_count || 0})</span> </div> <button onclick="togglePluginStatus(${p.id}, ${p.enabled})" class="px-3 py-1.5 text-xs rounded-xl transition-colors ${p.enabled ? 'bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-300 hover:bg-red-200 dark:hover:bg-red-900/60' : 'bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 hover:bg-emerald-200 dark:hover:bg-emerald-900/60'}"> ${p.enabled ? '<i class="fa-solid fa-power-off mr-1"></i>禁用' : '<i class="fa-solid fa-power-on mr-1"></i>启用'} </button> </div> </div> ${p.dependencies && JSON.parse(p.dependencies).length > 0 ? ` <div class="mt-3 pt-3 border-t border-slate-100"> <div class="text-[10px] text-slate-400 mb-1.5"><i class="fa-solid fa-link mr-1"></i>依赖: ${JSON.parse(p.dependencies).length} 个</div> <div class="flex flex-wrap gap-1"> ${JSON.parse(p.dependencies).map(d => `<span class="text-[10px] px-2 py-0.5 bg-slate-100 text-slate-600 rounded-lg">${d}</span>`).join('')} </div> </div>` : ''} </div> </div>`; }).join(''); } function updateStats(plugins) { const stats = { recon: 0, privesc: 0, lateral: 0, report: 0, automation: 0, utility: 0 }; plugins.forEach(p => { const cat = p.category || 'utility'; if (stats[cat] !== undefined) stats[cat]++; }); Object.keys(stats).forEach(k => { const el = document.getElementById('stat-' + k); if (el) el.textContent = stats[k]; }); document.getElementById('stat-total').textContent = plugins.length; } function showPluginDetail(id) { currentPluginId = id; reviewRating = 0; fetch('/api/plugins/' + id) .then(r => r.json()) .then(data => { if (!data.success) return; const p = data.data; document.getElementById('modal-plugin-name').textContent = p.name; document.getElementById('modal-plugin-version').textContent = 'v' + p.version; document.getElementById('modal-plugin-author').textContent = p.author || '-'; document.getElementById('modal-plugin-type').textContent = p.type || '-'; document.getElementById('modal-plugin-category').textContent = p.category || '-'; document.getElementById('modal-plugin-license').textContent = p.license || '-'; document.getElementById('modal-plugin-desc').textContent = p.description || '-'; const toggleBtn = document.getElementById('modal-toggle-btn'); if (p.enabled) { toggleBtn.className = 'px-4 py-2 text-sm rounded-xl font-medium transition-colors flex items-center gap-x-1.5 bg-red-100 hover:bg-red-200 text-red-700'; toggleBtn.innerHTML = '<i class="fa-solid fa-power-off"></i> 禁用'; } else { toggleBtn.className = 'px-4 py-2 text-sm rounded-xl font-medium transition-colors flex items-center gap-x-1.5 bg-emerald-100 hover:bg-emerald-200 text-emerald-700'; toggleBtn.innerHTML = '<i class="fa-solid fa-power-on"></i> 启用'; } loadRatingSummary(id); loadReviews(id); loadDependencies(id); loadUpdateStatus(id); document.getElementById('plugin-detail-modal').classList.remove('hidden'); }) .catch(err => showToast('加载插件详情失败', 'error')); } function loadRatingSummary(pluginId) { fetch('/api/plugins/' + pluginId + '/rating') .then(r => r.json()) .then(data => { if (!data.success) return; const s = data.data; document.getElementById('modal-rating-overall').textContent = s.overall.toFixed(1); document.getElementById('modal-rating-count').textContent = '(' + s.count + ' 条评论)'; for (let i = 1; i <= 5; i++) { const star = document.getElementById('star-' + i); star.className = i <= Math.round(s.overall) ? 'fa-solid fa-star text-amber-400' : 'fa-regular fa-star text-slate-300'; } const total = s.count || 1; for (let i = 1; i <= 5; i++) { const count = s.stars ? s.stars[i-1] || 0 : 0; document.getElementById('star-bar-' + i).style.width = (count / total * 100) + '%'; document.getElementById('star-count-' + i).textContent = count; } }); } function loadReviews(pluginId) { fetch('/api/plugins/' + pluginId + '/reviews') .then(r => r.json()) .then(data => { const list = document.getElementById('review-list'); if (!data.success || !data.data || data.data.length === 0) { list.innerHTML = '<div class="text-xs text-slate-400">暂无评论</div>'; return; } list.innerHTML = data.data.map(r => { const stars = Array(5).fill(0).map((_, i) => i < r.rating ? '<i class="fa-solid fa-star text-amber-400 text-xs"></i>' : '<i class="fa-regular fa-star text-slate-300 text-xs"></i>' ).join(''); return `<div class="bg-white/50 rounded-xl p-3 border border-amber-100"> <div class="flex items-center justify-between mb-1"> <span class="text-xs font-semibold text-slate-700">${r.username}</span> <span class="text-[10px] text-slate-400">${new Date(r.created_at).toLocaleDateString()}</span> </div> <div class="flex gap-0.5 mb-1.5">${stars}</div> <div class="text-xs text-slate-600">${r.comment || ''}</div> </div>`; }).join(''); }); } function loadDependencies(pluginId) { fetch('/api/plugins/' + pluginId + '/dependencies') .then(r => r.json()) .then(data => { const list = document.getElementById('dependency-list'); if (!data.success || !data.data || data.data.length === 0) { list.innerHTML = '<div class="text-xs text-slate-500">无依赖</div>'; return; } list.innerHTML = data.data.map(d => `<div class="flex items-center justify-between text-xs"> <div class="flex items-center gap-2"> <span class="${d.satisfied ? 'text-emerald-600' : 'text-amber-600'}">${d.name}</span> <span class="text-slate-400">${d.required_version}</span> ${d.optional ? '<span class="text-[10px] px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded">可选</span>' : ''} </div> <span class="text-[10px] px-2 py-0.5 rounded ${d.satisfied ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}">${d.installed ? (d.satisfied ? '已满足' : '版本不符') : '未安装'}</span> </div>`).join(''); }); } function loadUpdateStatus(pluginId) { fetch('/api/plugins/' + pluginId + '/update-status') .then(r => r.json()) .then(data => { const container = document.getElementById('update-status-detail'); if (!data.success) { container.innerHTML = '<div class="text-xs text-slate-500">无法获取更新状态</div>'; return; } const s = data.data; if (s.update_available) { container.innerHTML = `<div class="flex items-center justify-between"> <span class="text-xs text-slate-600">当前版本</span> <span class="text-xs font-medium text-slate-700">${s.current_version || '-'}</span> </div> <div class="flex items-center justify-between"> <span class="text-xs text-slate-600">最新版本</span> <span class="text-xs font-medium text-red-600">${s.latest_version}</span> </div> ${s.release_notes ? `<div class="mt-2 p-2 bg-red-50 rounded-lg text-[10px] text-red-700">${s.release_notes}</div>` : ''} <button onclick="updatePlugin(${pluginId})" class="mt-3 w-full px-3 py-2 bg-red-600 hover:bg-red-700 text-white rounded-xl text-xs font-medium transition-colors"> <i class="fa-solid fa-circle-up mr-1"></i>一键更新 </button>`; } else { container.innerHTML = `<div class="flex items-center justify-center text-xs text-emerald-600 py-2"> <i class="fa-solid fa-check-circle mr-1"></i>已是最新版本 </div> <div class="text-[10px] text-slate-400 text-center">上次检查: ${s.last_checked_at ? new Date(s.last_checked_at).toLocaleString() : '从未'}</div>`; } }); } function setReviewRating(rating) { reviewRating = rating; document.querySelectorAll('.star-btn').forEach((btn, i) => { const icon = btn.querySelector('i'); if (i < rating) { icon.className = 'fa-solid fa-star text-amber-400'; } else { icon.className = 'fa-regular fa-star'; } }); } function submitReview() { if (reviewRating === 0) { showToast('请选择评分', 'warning'); return; } const comment = document.getElementById('review-comment').value; fetch('/api/plugins/' + currentPluginId + '/reviews', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ rating: reviewRating, comment: comment }) }).then(r => r.json()).then(data => { if (data.success) { showToast('评价提交成功', 'success'); loadRatingSummary(currentPluginId); loadReviews(currentPluginId); document.getElementById('review-comment').value = ''; reviewRating = 0; document.querySelectorAll('.star-btn i').forEach(i => i.className = 'fa-regular fa-star'); } else { showToast('提交失败: ' + (data.error || ''), 'error'); } }); } function togglePluginStatus(id, enabled) { fetch('/api/plugins/' + id + '/toggle', { method: 'POST' }) .then(r => r.json()) .then(data => { if (data.success) { showToast(enabled ? '插件已禁用' : '插件已启用', 'success'); loadPlugins(); } else { showToast('操作失败', 'error'); } }); } function togglePlugin() { togglePluginStatus(currentPluginId, document.getElementById('modal-plugin-name').dataset.enabled === 'true'); closeModal('plugin-detail-modal'); } function deletePlugin() { if (!confirm('确定要删除这个插件吗？')) return; fetch('/api/plugins/' + currentPluginId, { method: 'DELETE' }) .then(r => r.json()) .then(data => { if (data.success) { showToast('插件已删除', 'success'); closeModal('plugin-detail-modal'); loadPlugins(); } else { showToast('删除失败', 'error'); } }); } function exportPlugin() { fetch('/api/plugins/' + currentPluginId + '/export') .then(r => r.blob()) .then(blob => { const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = 'plugin-' + currentPluginId + '.json'; a.click(); URL.revokeObjectURL(url); showToast('插件导出成功', 'success'); }) .catch(err => showToast('导出失败', 'error')); } function updatePlugin(id) { fetch('/api/plugins/' + id + '/update', { method: 'POST' }) .then(r => r.json()) .then(data => { if (data.success) { showToast('插件更新成功', 'success'); loadUpdateStatus(id); loadPlugins(); } else { showToast('更新失败: ' + (data.error || ''), 'error'); } }); } function showCreatePluginModal() { document.getElementById('create-name').value = ''; document.getElementById('create-version').value = '1.0.0'; document.getElementById('create-desc').value = ''; document.getElementById('create-author').value = ''; document.getElementById('create-license').value = 'MIT'; document.getElementById('create-homepage').value = ''; document.getElementById('create-plugin-modal').classList.remove('hidden'); } function createPlugin() { const data = { name: document.getElementById('create-name').value, version: document.getElementById('create-version').value, description: document.getElementById('create-desc').value, author: document.getElementById('create-author').value, type: document.getElementById('create-type').value, category: document.getElementById('create-category').value, license: document.getElementById('create-license').value, homepage: document.getElementById('create-homepage').value, }; if (!data.name) { showToast('请输入插件名称', 'warning'); return; } fetch('/api/plugins', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) }).then(r => r.json()).then(data => { if (data.success) { showToast('插件创建成功', 'success'); closeModal('create-plugin-modal'); loadPlugins(); } else { showToast('创建失败: ' + (data.error || ''), 'error'); } }); } function showImportModal() { document.getElementById('import-file').value = ''; document.getElementById('import-preview').classList.add('hidden'); document.getElementById('import-modal').classList.remove('hidden'); } function handleImportFile(input) { const file = input.files[0]; if (!file) return; const reader = new FileReader(); reader.onload = function(e) { const preview = document.getElementById('import-preview'); preview.classList.remove('hidden'); preview.querySelector('div').textContent = e.target.result.substring(0, 500) + (e.target.result.length > 500 ? '...' : ''); }; reader.readAsText(file); } function importPlugin() { const input = document.getElementById('import-file'); const file = input.files[0]; if (!file) { showToast('请选择文件', 'warning'); return; } const formData = new FormData(); formData.append('file', file); fetch('/api/plugins/import', { method: 'POST', body: formData }).then(r => r.json()).then(data => { if (data.success) { showToast('插件导入成功', 'success'); closeModal('import-modal'); loadPlugins(); } else { showToast('导入失败: ' + (data.error || ''), 'error'); } }); } function checkAllUpdates() { fetch('/api/plugins/check-updates', { method: 'POST' }) .then(r => r.json()) .then(data => { if (data.success) { showToast('更新检查完成', 'success'); loadPlugins(); refreshUpdateSummary(); } else { showToast('检查失败', 'error'); } }); } function refreshUpdateSummary() { fetch('/api/plugins/update-summary') .then(r => r.json()) .then(data => { const container = document.getElementById('update-summary'); const status = document.getElementById('update-status'); if (!data.success) return; status.textContent = '上次检查: ' + (data.last_checked ? new Date(data.last_checked).toLocaleString() : '从未'); if (data.available_count > 0) { container.innerHTML = `<div class="p-3 bg-red-50 border border-red-200 rounded-xl"> <div class="text-xs font-medium text-red-700"><i class="fa-solid fa-circle-up mr-1"></i>${data.available_count} 个插件有更新</div> <div class="text-[10px] text-red-600 mt-1">点击插件查看详情并更新</div> </div>`; } else { container.innerHTML = `<div class="p-3 bg-emerald-50 border border-emerald-200 rounded-xl"> <div class="text-xs font-medium text-emerald-700"><i class="fa-solid fa-check-circle mr-1"></i>所有插件都是最新版本</div> </div>`; } }); } function closeModal(id) { document.getElementById(id).classList.add('hidden'); } function refreshPlugins() { loadPlugins(); } document.addEventListener('DOMContentLoaded', function() { loadPlugins(); refreshUpdateSummary(); document.getElementById('plugin-search').addEventListener('input', function() { loadPlugins(); }); document.getElementById('plugin-category').addEventListener('change', function() { loadPlugins(); }); document.getElementById('plugin-type').addEventListener('change', function() { loadPlugins(); }); });

